import{_ as r,c as i,o as a,ai as s}from"./chunks/framework.TS84ywiI.js";const u=JSON.parse('{"title":"如何保证 redis 的高并发和高可用？","description":"","frontmatter":{},"headers":[],"relativePath":"high-concurrency/how-to-ensure-high-concurrency-and-high-availability-of-redis.md","filePath":"high-concurrency/how-to-ensure-high-concurrency-and-high-availability-of-redis.md"}'),t={name:"high-concurrency/how-to-ensure-high-concurrency-and-high-availability-of-redis.md"};function d(n,e,o,h,c,l){return a(),i("div",null,e[0]||(e[0]=[s('<h1 id="如何保证-redis-的高并发和高可用" tabindex="-1">如何保证 redis 的高并发和高可用？ <a class="header-anchor" href="#如何保证-redis-的高并发和高可用" aria-label="Permalink to &quot;如何保证 redis 的高并发和高可用？&quot;">​</a></h1><h2 id="面试题" tabindex="-1">面试题 <a class="header-anchor" href="#面试题" aria-label="Permalink to &quot;面试题&quot;">​</a></h2><p>如何保证 redis 的高并发和高可用？redis 的主从复制原理能介绍一下么？redis 的哨兵原理能介绍一下么？</p><h2 id="面试官心理分析" tabindex="-1">面试官心理分析 <a class="header-anchor" href="#面试官心理分析" aria-label="Permalink to &quot;面试官心理分析&quot;">​</a></h2><p>其实问这个问题，主要是考考你，redis 单机能承载多高并发？如果单机扛不住如何扩容扛更多的并发？redis 会不会挂？既然 redis 会挂那怎么保证 redis 是高可用的？</p><p>其实针对的都是项目中你肯定要考虑的一些问题，如果你没考虑过，那确实你对生产系统中的问题思考太少。</p><h2 id="面试题剖析" tabindex="-1">面试题剖析 <a class="header-anchor" href="#面试题剖析" aria-label="Permalink to &quot;面试题剖析&quot;">​</a></h2><p>如果你用 redis 缓存技术的话，肯定要考虑如何用 redis 来加多台机器，保证 redis 是高并发的，还有就是如何让 redis 保证自己不是挂掉以后就直接死掉了，即 redis 高可用。</p><p>由于此节内容较多，因此，会分为两个小节进行讲解。</p><ul><li><a href="./redis-master-slave">redis 主从架构</a></li><li><a href="./redis-sentinel">redis 基于哨兵实现高可用</a></li></ul><p>redis 实现<strong>高并发</strong>主要依靠<strong>主从架构</strong>，一主多从，一般来说，很多项目其实就足够了，单主用来写入数据，单机几万 QPS，多从用来查询数据，多个从实例可以提供每秒 10w 的 QPS。</p><p>如果想要在实现高并发的同时，容纳大量的数据，那么就需要 redis 集群，使用 redis 集群之后，可以提供每秒几十万的读写并发。</p><p>redis 高可用，如果是做主从架构部署，那么加上哨兵就可以了，就可以实现，任何一个实例宕机，可以进行主备切换。</p>',13)]))}const _=r(t,[["render",d]]);export{u as __pageData,_ as default};
